INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (140, 'National Minimum Wage Review and Adjustment Mechanism', 'Reform of the National Minimum Wage Commission''s review methodology to better balance employment creation with worker protection. Parliamentary hearings have repeatedly examined the NMW''s impact on employment in vulnerable sectors (agriculture, domestic work) and the adequacy of the annual adjustment formula.', 'labour_market', 'under_review', 3, 3, 'medium_term', 2, 'Employment and Labour', 'Department of Employment and Labour', 'national-minimum-wage-review-and-adjustment-mechanism', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (141, 'CCMA Capacity and Case Resolution Reform', 'Expansion of CCMA commissioner capacity and digitisation of dispute resolution to reduce case backlogs. The committee has tracked CCMA performance quarterly, noting rising caseloads, understaffing, and delays in conciliation and arbitration outcomes.', 'labour_market', 'debated', 4, 3, 'quick_win', 2, 'Employment and Labour', 'Department of Employment and Labour', 'ccma-capacity-and-case-resolution-reform', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (142, 'Employment Tax Incentive (ETI) Extension and Expansion', 'Extension and broadening of the ETI youth wage subsidy to increase youth employment absorption. Committee has examined ETI take-up rates, deadweight losses, and proposals to expand beyond the current age and wage thresholds.', 'labour_market', 'debated', 4, 4, 'quick_win', 2, 'Employment and Labour', 'Department of Employment and Labour', 'employment-tax-incentive-eti-extension-and-expansion', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (143, 'Unemployment Insurance Fund (UIF) Governance and Benefit Reform', 'Overhaul of UIF benefit structure, claims processing, and investment governance following audit findings of mismanagement. The committee has scrutinised UIF quarterly performance, investment losses, and the gap between contribution income and benefit payouts.', 'labour_market', 'under_review', 3, 2, 'medium_term', 2, 'Employment and Labour', 'Department of Employment and Labour', 'unemployment-insurance-fund-uif-governance-and-benefit-reform', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (144, 'Compensation Fund Turnaround and Claims Backlog', 'Clearance of the Compensation Fund''s multi-year claims backlog and modernisation of the occupational injury claims system. Parliamentary oversight has documented systemic processing failures, IT system deficiencies, and employer non-compliance.', 'labour_market', 'stalled', 3, 2, 'medium_term', 2, 'Employment and Labour', 'Department of Employment and Labour', 'compensation-fund-turnaround-and-claims-backlog', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (145, 'Labour Activation Programme for Long-Term Unemployed', 'Active labour market programme combining skills training, work experience, and placement services targeting the long-term unemployed and discouraged work-seekers. The committee has held dedicated workshops on activation strategies and examined international models.', 'labour_market', 'proposed', 3, 4, 'medium_term', 2, 'Employment and Labour', 'Department of Employment and Labour', 'labour-activation-programme-for-long-term-unemployed', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (146, 'Section 189 Retrenchment Process Reform', 'Amendments to Labour Relations Act sections 189 and 189A governing large-scale retrenchments, including enhanced consultation requirements, mandatory social plans, and improved severance frameworks. Committee workshops have examined the retrenchment process following major job losses.', 'labour_market', 'debated', 2, 3, 'long_term', 2, 'Employment and Labour', 'Department of Employment and Labour', 'section-189-retrenchment-process-reform', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (147, 'Productivity SA and Workplace Competitiveness Support', 'Strengthening Productivity SA''s capacity to provide turnaround assistance to distressed companies and sectors, preventing unnecessary job losses through workplace restructuring rather than retrenchment.', 'labour_market', 'debated', 4, 3, 'quick_win', 2, 'Employment and Labour', 'Department of Employment and Labour', 'productivity-sa-and-workplace-competitiveness-support', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (148, 'Informal Economy Integration and Worker Protection', 'Extension of basic labour protections and social security coverage to informal economy workers, including street traders, domestic workers, and platform gig workers. Committee hearings have examined the gap between formal labour law and the reality of informally employed South Africans.', 'labour_market', 'proposed', 2, 3, 'long_term', 2, 'Employment and Labour', 'Department of Employment and Labour', 'informal-economy-integration-and-worker-protection', 1);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (149, 'NEDLAC Social Compact on Employment and Growth', 'Strengthening NEDLAC''s capacity to broker binding social compacts between government, business, and labour on key reform areas — particularly around wage moderation, investment commitments, and structural reform sequencing.', 'labour_market', 'debated', 3, 3, 'medium_term', 2, 'Employment and Labour', 'Department of Employment and Labour', 'nedlac-social-compact-on-employment-and-growth', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (150, 'SAPS Detective Service Capacity and Case Clearance', 'Expansion of SAPS detective capacity to improve case clearance rates, particularly for serious and violent crimes. Committee oversight has documented critical shortages in detective-to-case ratios, forensic backlogs, and the impact on prosecution success rates.', 'crime_safety', 'debated', 3, 4, 'medium_term', 5, 'Police', 'Department of Police', 'saps-detective-service-capacity-and-case-clearance', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (151, 'Anti-Extortion and Construction Mafia Task Force', 'Establishment of dedicated anti-extortion units targeting construction site extortion, business protection rackets, and organised criminal syndicates disrupting infrastructure development and private investment.', 'crime_safety', 'proposed', 3, 5, 'quick_win', 5, 'Police', 'Department of Police', 'anti-extortion-and-construction-mafia-task-force', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (152, 'Gender-Based Violence Prevention and Response Strategy', 'Implementation of the National Strategic Plan on GBV including dedicated SAPS Family Violence, Child Protection and Sexual Offences (FCS) units, Thuthuzela Care Centres, and the National Register for Sex Offenders.', 'crime_safety', 'under_review', 3, 3, 'medium_term', 5, 'Police', 'Department of Police', 'gender-based-violence-prevention-and-response-strategy', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (153, 'IPID Independence and Police Accountability', 'Strengthening the Independent Police Investigative Directorate''s operational independence, investigative capacity, and prosecution referral effectiveness to ensure meaningful accountability for police misconduct.', 'crime_safety', 'debated', 3, 2, 'medium_term', 5, 'Police', 'Department of Police', 'ipid-independence-and-police-accountability', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (154, 'Private Security Industry Regulation (PSIRA) Reform', 'Reform of PSIRA''s regulatory framework to address the growing private security sector (larger than SAPS), including ownership rules, training standards, and coordination with public policing.', 'crime_safety', 'debated', 4, 2, 'medium_term', 5, 'Police', 'Department of Police', 'private-security-industry-regulation-psira-reform', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (155, 'Illegal Mining and Resource Crime Combatting', 'Coordinated strategy to combat illegal mining (zama-zama operations), including inter-departmental coordination between SAPS, DMRE, and immigration authorities, and addressing the environmental and safety hazards of abandoned mines.', 'crime_safety', 'under_review', 3, 3, 'medium_term', 5, 'Police', 'Department of Police', 'illegal-mining-and-resource-crime-combatting', 4);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (156, 'Community Policing Forum Revitalisation', 'Revitalisation of Community Policing Forums (CPFs) as a mechanism for civilian oversight and community safety partnerships, including sustainable funding models and integration with municipal safety plans.', 'crime_safety', 'stalled', 3, 2, 'medium_term', 5, 'Police', 'Department of Police', 'community-policing-forum-revitalisation', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (157, 'SANDF Deployment in Support of SAPS Border Security', 'Rationalisation of SANDF deployment for internal policing support, border security, and cross-border crime prevention, including cost-effectiveness evaluation and exit strategy development.', 'crime_safety', 'under_review', 3, 2, 'quick_win', 5, 'Police', 'Department of Police', 'sandf-deployment-in-support-of-saps-border-security', 4);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (158, 'NPA Prosecution Capacity and Independence', 'Rebuilding NPA prosecution capacity, particularly for complex commercial crime, corruption, and organised crime cases. Committee has tracked NPA vacancy rates, conviction rates, and the implementation of Zondo Commission referrals.', 'corruption_governance', 'under_review', 3, 4, 'medium_term', 5, 'Justice and Constitutional Development', 'Department of Justice and Constitutional Development', 'npa-prosecution-capacity-and-independence', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (159, 'Court Case Backlog and Judicial Efficiency', 'Reduction of the court case backlog through additional judicial officers, court modernisation, and case flow management. The committee has examined delays in criminal and civil proceedings that undermine access to justice and investor confidence.', 'crime_safety', 'debated', 3, 3, 'medium_term', 5, 'Justice and Constitutional Development', 'Department of Justice and Constitutional Development', 'court-case-backlog-and-judicial-efficiency', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (160, 'SIU Special Tribunal and Asset Recovery Acceleration', 'Strengthening the SIU''s Special Tribunal for civil recovery of state losses from corruption and fraud. The committee has monitored SIU investigation outcomes, recovery rates, and the pipeline of matters referred from the Zondo Commission.', 'corruption_governance', 'under_review', 4, 3, 'quick_win', 5, 'Justice and Constitutional Development', 'Department of Justice and Constitutional Development', 'siu-special-tribunal-and-asset-recovery-acceleration', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (161, 'Legal Aid South Africa Capacity and Access to Justice', 'Expansion of Legal Aid SA''s capacity to provide legal representation in civil and criminal matters, particularly for vulnerable populations and in rural areas where access to legal services is limited.', 'crime_safety', 'debated', 3, 2, 'medium_term', 5, 'Justice and Constitutional Development', 'Department of Justice and Constitutional Development', 'legal-aid-south-africa-capacity-and-access-to-justice', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (162, 'TRC Recommendations Implementation', 'Implementation of outstanding Truth and Reconciliation Commission recommendations, including reparations, prosecutions of apartheid-era crimes, and institutional memory preservation. The committee has held dedicated stakeholder engagements on implementation progress.', 'government_capacity', 'stalled', 2, 1, 'long_term', 5, 'Justice and Constitutional Development', 'Department of Justice and Constitutional Development', 'trc-recommendations-implementation', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (163, 'Cybercrime and Digital Evidence Legislation', 'Implementation of the Cybercrimes Act including establishment of designated cybercrime courts, digital forensic capacity in SAPS, and international cooperation frameworks for cross-border digital crime.', 'crime_safety', 'under_review', 3, 3, 'medium_term', 5, 'Justice and Constitutional Development', 'Department of Justice and Constitutional Development', 'cybercrime-and-digital-evidence-legislation', 1);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (164, 'Bulk Water Infrastructure Investment Programme', 'Accelerated investment in bulk water supply infrastructure including new dams, inter-basin transfers, and treatment works to address growing demand-supply gaps. The committee has examined the national water infrastructure programme''s implementation delays and cost overruns.', 'water', 'under_review', 3, 4, 'long_term', 1, 'Water and Sanitation', 'Department of Water and Sanitation', 'bulk-water-infrastructure-investment-programme', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (165, 'Municipal Water Loss Reduction (Non-Revenue Water)', 'National programme to reduce municipal non-revenue water losses from the current ~40% average to below 25%, through leak detection, meter replacement, pipe rehabilitation, and pressure management. Committee oversight has documented massive water losses in municipalities.', 'water', 'debated', 4, 3, 'medium_term', 1, 'Water and Sanitation', 'Department of Water and Sanitation', 'municipal-water-loss-reduction-non-revenue-water', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (166, 'Water Services Amendment Bill Implementation', 'Implementation of the Water Services Amendment Bill to strengthen regulation of water service authorities, improve water quality standards enforcement, and address the decline in Blue Drop and Green Drop audit scores.', 'water', 'drafted', 3, 3, 'medium_term', 1, 'Water and Sanitation', 'Department of Water and Sanitation', 'water-services-amendment-bill-implementation', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (167, 'Water Board Governance and Financial Sustainability', 'Reform of water board governance structures, financial sustainability models, and accountability frameworks. Committee has scrutinised annual reports of Rand Water, Umgeni, Lepelle Northern, and other boards documenting governance failures and debt accumulation.', 'water', 'under_review', 3, 2, 'medium_term', 1, 'Water and Sanitation', 'Department of Water and Sanitation', 'water-board-governance-and-financial-sustainability', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (168, 'Water Use Licensing and Allocation Reform', 'Reform of the water use licensing system to accelerate processing of water use licence applications, address the backlog, and ensure equitable allocation between agricultural, industrial, and domestic users including historically disadvantaged communities.', 'water', 'debated', 3, 3, 'medium_term', 1, 'Water and Sanitation', 'Department of Water and Sanitation', 'water-use-licensing-and-allocation-reform', 4);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (169, 'Catchment Management Agency Establishment', 'Establishment of the remaining Catchment Management Agencies (CMAs) to decentralise water resource management and improve local stakeholder participation in water allocation and protection decisions.', 'water', 'stalled', 3, 2, 'long_term', 1, 'Water and Sanitation', 'Department of Water and Sanitation', 'catchment-management-agency-establishment', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (170, 'Johannesburg Water and Municipal Water Utility Reform', 'Restructuring of failing municipal water utilities, particularly Johannesburg Water, to restore service delivery, address infrastructure decay, and ensure financial sustainability. Committee has examined the crisis in metropolitan water services.', 'water', 'debated', 3, 3, 'medium_term', 1, 'Water and Sanitation', 'Department of Water and Sanitation', 'johannesburg-water-and-municipal-water-utility-reform', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (171, 'Sanitation Infrastructure and Bucket Eradication', 'Completion of the bucket sanitation eradication programme and upgrading of wastewater treatment works to reduce pollution of water sources. Committee has tracked the slow progress of sanitation infrastructure delivery.', 'water', 'stalled', 3, 2, 'long_term', 1, 'Water and Sanitation', 'Department of Water and Sanitation', 'sanitation-infrastructure-and-bucket-eradication', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (172, 'Just Energy Transition Implementation Plan (JET-IP)', 'Implementation of the Just Energy Transition Investment Plan including coal plant decommissioning timelines, renewable energy deployment, worker transition support, and community economic diversification in coal-dependent regions like Mpumalanga.', 'climate_environment', 'under_review', 3, 4, 'long_term', 1, 'Forestry, Fisheries and the Environment', 'Department of Forestry, Fisheries and the Environment', 'just-energy-transition-implementation-plan-jet-ip', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (173, 'Carbon Tax Rate Escalation and Revenue Recycling', 'Phased escalation of the carbon tax rate from the current low base, with clear revenue recycling mechanisms to fund climate adaptation, renewable energy, and just transition programmes. South Africa''s carbon tax has been too low to drive meaningful emissions reduction.', 'climate_environment', 'debated', 3, 3, 'medium_term', 1, 'Forestry, Fisheries and the Environment', 'Department of Forestry, Fisheries and the Environment', 'carbon-tax-rate-escalation-and-revenue-recycling', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (174, 'Climate Change Adaptation Infrastructure', 'Investment in climate adaptation infrastructure including drought-resilient water systems, flood defences, fire management, and climate-smart agriculture. Committee has examined the increasing frequency of extreme weather events and their economic impact.', 'climate_environment', 'proposed', 3, 3, 'long_term', 1, 'Forestry, Fisheries and the Environment', 'Department of Forestry, Fisheries and the Environment', 'climate-change-adaptation-infrastructure', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (175, 'SANParks and Protected Area Expansion', 'Expansion of the protected area network toward the 30x30 biodiversity target, including marine protected areas, community-based conservation, and addressing the funding gap for SANParks operations.', 'climate_environment', 'debated', 3, 2, 'long_term', 1, 'Forestry, Fisheries and the Environment', 'Department of Forestry, Fisheries and the Environment', 'sanparks-and-protected-area-expansion', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (176, 'Marine Fisheries Reform and Small-Scale Fisher Rights', 'Reform of marine fisheries allocation to address historical inequities, support small-scale fishers, combat illegal fishing, and ensure sustainable stock management. The committee has examined the crisis in fishing rights allocation and sector transformation.', 'climate_environment', 'under_review', 3, 2, 'medium_term', 1, 'Forestry, Fisheries and the Environment', 'Department of Forestry, Fisheries and the Environment', 'marine-fisheries-reform-and-small-scale-fisher-rights', 5);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (177, 'Green Hydrogen and Critical Minerals Regulatory Framework', 'Development of the regulatory and permitting framework for green hydrogen production and critical minerals processing, positioning South Africa to capture global demand for transition minerals (platinum group metals, manganese, vanadium).', 'climate_environment', 'proposed', 3, 4, 'long_term', 1, 'Forestry, Fisheries and the Environment', 'Department of Forestry, Fisheries and the Environment', 'green-hydrogen-and-critical-minerals-regulatory-framework', 4);
INSERT INTO policy_ideas (id, title, description, binding_constraint, current_status, feasibility_rating, growth_impact_rating, time_horizon, reform_package, source_committee, responsible_department, slug, times_raised) VALUES (178, 'Forestry Sector Revitalisation and Timber Value Chain', 'Revitalisation of the commercial forestry sector including SAFCOL restructuring, plantation expansion, fire management investment, and support for community forestry enterprises. Committee has tracked the decline of state forestry operations.', 'climate_environment', 'stalled', 3, 2, 'medium_term', 1, 'Forestry, Fisheries and the Environment', 'Department of Forestry, Fisheries and the Environment', 'forestry-sector-revitalisation-and-timber-value-chain', 5);
